sql:
SELECT c.country_name, h.life_expectancy, h.adult_mortality, h.infant_deaths
FROM countries c
INNER JOIN health_data h ON c.country_id = h.country_id;

SELECT country_id, total_expenditure
FROM healthcare_expenditure
WHERE total_expenditure > 10;

external_knowledge:
- 'fairly long life span' is interpreted as an average life expectancy greater than 70 years;
- 'relatively low risk of adult mortality' refers to an average adult mortality rate of less than 200 per 100,000;
- 'analyzed by data scientists' indicates that the data was accessed by users from the 'Data Science' department.
